import{c as r,o as l,b as s}from"./index-DJVzbUTg.js";const n="/docs/email/email.jpg",i={class:"markdown-body"},c={__name:"Email: Подключение",setup(e,{expose:t}){return t({frontmatter:{}}),(a,o)=>(l(),r("div",i,[...o[0]||(o[0]=[s('<h1>Инструкция по подключению Email (на примере Gmail)</h1><hr><ol><li>Зайдите в раздел <strong>Настройки → Интеграции → Email</strong>.</li><li>Нажмите <strong>«Добавить аккаунт»</strong>.<br> Выберите вид аккаунта — <strong>Email</strong>.<br> В поле <strong>«Провайдер»</strong> выберите <strong>Gmail</strong>.</li><li>Заполните поля: <ul><li><strong>Адрес отправки</strong> — ваш email (например, <code>example@gmail.com</code>).</li><li><strong>Пользователь</strong> — оставьте пустым, если совпадает с адресом отправки.</li><li><strong>Пароль для приложений</strong> — специальный пароль, созданный в настройках безопасности Google.</li><li><strong>SMTP сервер</strong> — <code>smtp.gmail.com</code> (подставится автоматически при выборе Gmail).</li><li><strong>Порт SMTP</strong> — <code>587</code>.</li></ul></li><li>Нажмите <strong>«Сохранить»</strong>.</li></ol><p><img src="'+n+'" alt="Описание картинки"></p><blockquote><p>После сохранения аккаунт <strong>Email</strong> можно добавить в каскадную группу аналогично <strong>SMS</strong>.</p></blockquote>',5)])]))}};export{c as default};
